import{_ as a,o as r,c as t,a4 as o}from"./chunks/framework.m9mi3vzv.js";const p=JSON.parse('{"title":"Interface: RenderRoot · ui","description":"","frontmatter":{"title":"Interface: RenderRoot · ui"},"headers":[],"relativePath":"api/ui/interfaces/RenderRoot.md","filePath":"api/ui/interfaces/RenderRoot.md"}'),s={name:"api/ui/interfaces/RenderRoot.md"};function i(n,e,l,d,h,c){return r(),t("div",null,[...e[0]||(e[0]=[o(`<p><a href="./../">@jsvision/ui</a> / RenderRoot</p><h1 id="interface-renderroot" tabindex="-1">Interface: RenderRoot <a class="header-anchor" href="#interface-renderroot" aria-label="Permalink to &quot;Interface: RenderRoot&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L36" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:36</a></p><p>Mounts a view tree and renders it to a screen buffer. This is the seam a host (or the higher-level app shell / event loop) wires the terminal to.</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="buffer" tabindex="-1">buffer() <a class="header-anchor" href="#buffer" aria-label="Permalink to &quot;buffer()&quot;">​</a></h3><blockquote><p><strong>buffer</strong>(): <code>ScreenBuffer</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L46" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:46</a></p><p>The live composed screen buffer — for host integration and tests.</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>ScreenBuffer</code></p><hr><h3 id="flush" tabindex="-1">flush() <a class="header-anchor" href="#flush" aria-label="Permalink to &quot;flush()&quot;">​</a></h3><blockquote><p><strong>flush</strong>(): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L42" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:42</a></p><p>Force a synchronous frame now, running any pending scheduled repaint immediately.</p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="mount" tabindex="-1">mount() <a class="header-anchor" href="#mount" aria-label="Permalink to &quot;mount()&quot;">​</a></h3><blockquote><p><strong>mount</strong>(<code>root</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L38" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:38</a></p><p>Mount a view tree: wire its scopes, run the first layout, and compose the first frame.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="root" tabindex="-1">root <a class="header-anchor" href="#root" aria-label="Permalink to &quot;root&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="originof" tabindex="-1">originOf() <a class="header-anchor" href="#originof" aria-label="Permalink to &quot;originOf()&quot;">​</a></h3><blockquote><p><strong>originOf</strong>(<code>view</code>): <a href="./Point.html"><code>Point</code></a> | <code>null</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L57" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:57</a></p><p>The view&#39;s <strong>absolute</strong> top-left cell as of the last time it was composed, or <code>null</code> if it was never composed (unmounted / not visible). The event loop uses this to translate a focused view&#39;s <code>desiredCaret()</code> into an absolute terminal cell. An origin survives partial repaints — a view unchanged this frame keeps its last origin — so the caret is never lost just because the focused view was outside the changed region.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="view" tabindex="-1">view <a class="header-anchor" href="#view" aria-label="Permalink to &quot;view&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><p>The view to locate (typically the focused leaf).</p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><a href="./Point.html"><code>Point</code></a> | <code>null</code></p><p>The absolute origin <code>{ x, y }</code>, or <code>null</code> if never composed.</p><hr><h3 id="resize" tabindex="-1">resize() <a class="header-anchor" href="#resize" aria-label="Permalink to &quot;resize()&quot;">​</a></h3><blockquote><p><strong>resize</strong>(<code>size</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L40" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:40</a></p><p>Resize the viewport, triggering a full re-layout and recompose.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="size" tabindex="-1">size <a class="header-anchor" href="#size" aria-label="Permalink to &quot;size&quot;">​</a></h5><p><a href="./Size2D.html"><code>Size2D</code></a></p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="serialize" tabindex="-1">serialize() <a class="header-anchor" href="#serialize" aria-label="Permalink to &quot;serialize()&quot;">​</a></h3><blockquote><p><strong>serialize</strong>(): <code>string</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L44" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:44</a></p><p>The last frame&#39;s damage-diff output (the escape sequences to apply); forces a flush if one is pending.</p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>string</code></p><hr><h3 id="setrevealaccelerators" tabindex="-1">setRevealAccelerators() <a class="header-anchor" href="#setrevealaccelerators" aria-label="Permalink to &quot;setRevealAccelerators()&quot;">​</a></h3><blockquote><p><strong>setRevealAccelerators</strong>(<code>on</code>, <code>scope?</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L68" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:68</a></p><p>Reveal (or hide) the hotkey-accelerator overlay for the next frame. While <code>on</code>, every widget that draws a <code>~X~</code> hotkey underlines its hot glyph. <code>scope</code> limits the reveal to a subtree (e.g. the active modal dialog); <code>null</code>/omitted reveals the whole tree. A change forces one coalesced full recompose on the next frame so the underlines appear/disappear together. Underlining does not change any cell width, so geometry never shifts.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="on" tabindex="-1">on <a class="header-anchor" href="#on" aria-label="Permalink to &quot;on&quot;">​</a></h5><p><code>boolean</code></p><p>Whether the overlay is revealed.</p><h5 id="scope" tabindex="-1">scope? <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;scope?&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a> | <code>null</code></p><p>The subtree to limit the reveal to, or <code>null</code> for the whole tree.</p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="settheme" tabindex="-1">setTheme() <a class="header-anchor" href="#settheme" aria-label="Permalink to &quot;setTheme()&quot;">​</a></h3><blockquote><p><strong>setTheme</strong>(<code>theme</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/8bf525e5bd4021be619a6e92851c4c020e1b707f/packages/ui/src/view/render-root.ts#L80" target="_blank" rel="noreferrer">ui/src/view/render-root.ts:80</a></p><p>Replace the active theme and force one coalesced full recompose, so every view repaints with the new colors on the next frame. A theme swap changes no geometry, so origins are preserved and the caret is not lost. Under the event loop&#39;s no-op schedule this only marks the frame dirty — call it through <code>EventLoop.setTheme</code> (or <code>flush()</code> directly) to actually push the frame.</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="theme" tabindex="-1">theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;theme&quot;">​</a></h5><p><code>Theme</code></p><p>The theme to switch to.</p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><h4 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h4><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">renderRoot.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setTheme</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(nordTheme);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">renderRoot.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flush</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// push the repainted frame</span></span></code></pre></div>`,84)])])}const b=a(s,[["render",i]]);export{p as __pageData,b as default};
